const getColorFromClass = (colorClass) => {
  if (!colorClass) return '#9CA3AF'; // default gray

  // Check for specific color names in the class string
  if (colorClass.includes('blue')) return '#3B82F6'; // Amigo
  if (colorClass.includes('red')) return '#EF4444'; // Compañero
  if (colorClass.includes('green')) return '#10B981'; // Explorador
  if (colorClass.includes('rose')) return '#BE123C'; // Viajero (Darker Wine Red as requested)
  if (colorClass.includes('yellow')) return '#EAB308'; // Guía
  if (colorClass.includes('amber')) return '#F59E0B'; // Aspirante
  if (colorClass.includes('orange')) return '#F97316'; // Guía Mayor Investido
  if (colorClass.includes('purple')) return '#A855F7'; // Guía Mayor
  if (colorClass.includes('gray')) return '#9CA3AF'; // Orientador
  if (colorClass.includes('rose')) return '#F43F5E'; // Viajero
  if (colorClass.includes('yellow')) return '#EAB308'; // Guía

  return '#9CA3AF'; // fallback
};

