  // ========================================
  useEffect(() => {
    const fetchData = async () => {
      try {
        // Portal member anonymous elevating session to bypass Firestore restrictive central doc rules
        if (portalMember && !auth.currentUser) {
          try {
            await signInAnonymously(auth);
            console.log('🛡️ Auto-elevated portal session');
          } catch (e) {
            console.warn('Could not auto-elevate session:', e);
          }
        }
        // En la web, si NO estamos autenticados (como admin o miembro), solo permitimos cargar la lista de usuarios
        // para que el login pueda funcionar con perfiles creados en otros equipos.
        if (!isAuthenticated && !portalMember && !window.electronAPI) {
          console.log('📡 Sincronizando usuarios y miembros para inicio de sesión...');
          const [cloudUsers, cloudMembers] = await Promise.all([
            dataService.readData('users'),
            dataService.readData('members')
          ]);
          
          if (cloudUsers && Array.isArray(cloudUsers) && cloudUsers.length > 0) {
            setUsers(cloudUsers);
          }
          if (cloudMembers && Array.isArray(cloudMembers) && cloudMembers.length > 0) {
            setMembers(cloudMembers);
          }
          return;
        }

        console.log('🔄 Cargando datos completos desde el almacenamiento...');
        const allData = await loadFromStorage();

        if (allData.members) setMembers(allData.members);
        // Initialize Transactions with Migration Check
        let initialTransactions = allData.transactions || [];

        // MIGRATION: Ensure Fixed Payments exist as real transactions
        if (allData.fixedPayments && allData.fixedPaymentConcepts) {
          allData.fixedPaymentConcepts.forEach(concept => {
            const payments = allData.fixedPayments[concept.id] || {};
            Object.entries(payments).forEach(([memberId, val]) => {
              if (val) {
                const txId = `fixed-${concept.id}-${memberId}`;
                // Find member name for description
                const member = (allData.members || []).find(m => m.id === memberId);
                const memberName = member ? `${member.firstName} ${member.lastName}` : 'Miembro';

                // Determine date and amount
                let date = getLocalISODate();
                let amount = concept.amount || 0;

                if (typeof val === 'string' && val.trim().length > 0) {
                  // Check if valid date
                  if (!isNaN(new Date(val).getTime())) {
                    date = val.includes('T') ? val.split('T')[0] : val;
                  }
                } else if (typeof val === 'object') {
                  if (val.date && !isNaN(new Date(val.date).getTime())) {
                    date = val.date.includes('T') ? val.date.split('T')[0] : val.date;
                  }
                  if (val.amount !== undefined) amount = val.amount;
                }

                const txIndex = initialTransactions.findIndex(t => t.id === txId);

                if (txIndex >= 0) {
                  // FORCE UPDATE existing transaction to ensure format is correct
                  initialTransactions[txIndex] = {
                    ...initialTransactions[txIndex],
                    category: concept.name,
                    description: concept.name,
                    responsibleId: memberId
                  };
                } else {
                  initialTransactions.push({
                    id: txId,
                    type: 'income',
                    category: concept.name,
                    description: concept.name,
                    amount: parseFloat(amount),
                    date: date,
                    memberId: memberId,
                    responsibleId: memberId, // Set responsibleId to show in table
                    status: 'official'
                  });
                }
              }
            });
          });
        }

        // MIGRATION: Fix legacy bulk quota transactions that have 'inc_1' or are missing responsibleId
        initialTransactions = initialTransactions.map(t => {
          if (t.category === 'inc_1') {
            t.category = 'Cuotas';
          }
          if ((t.description === 'Pago de Cuota Semanal (Masivo)' || t.description === 'Condonación de deuda (Waiver)') && !t.responsibleId && t.memberId) {
            t.responsibleId = t.memberId;
          }
          return t;
        });

        // MIGRATION: Migrate and clean up old $0 Waiver transactions from Finanzas
        // Convert them into waivedSaturdays arrays on the member object, then filter them out of transactions.
        if (allData.members) {
          const legacyWaivers = initialTransactions.filter(t => t.paymentMethod === 'Waiver' && t.description === 'Condonación de deuda (Waiver)' && t.amount === 0);

          if (legacyWaivers.length > 0) {
            const updatedMembers = [...allData.members];
            legacyWaivers.forEach(waiver => {
              const memberIndex = updatedMembers.findIndex(m => m.id === waiver.memberId);
              if (memberIndex !== -1) {
                const existingWaived = updatedMembers[memberIndex].waivedSaturdays || [];
                updatedMembers[memberIndex] = {
                  ...updatedMembers[memberIndex],
                  waivedSaturdays: [...new Set([...existingWaived, waiver.date])]
                };
              }
            });
            setMembers(updatedMembers);
            // Prune them from transactions array silently
            initialTransactions = initialTransactions.filter(t => !(t.paymentMethod === 'Waiver' && t.description === 'Condonación de deuda (Waiver)' && t.amount === 0));
          }
        }

        setTransactions(initialTransactions);
        
        // Robust loading for Activities
        if (allData.activities && Array.isArray(allData.activities) && allData.activities.length > 0) {
          setActivities(allData.activities);
        } else {
          // If missing in main payload, try direct fetch as fallback
          const directActs = await dataService.readData('activities');
          if (directActs && Array.isArray(directActs) && directActs.length > 0) {
            setActivities(directActs);
          }
        }

        // Robust loading for Points (Handle Object vs Array)
        if (allData.points) {
          const pointsData = allData.points;
          if (typeof pointsData === 'object' && !Array.isArray(pointsData)) {
            console.log('🔄 Autofix: Converting Points Map to List...');
            const flattened = Object.entries(pointsData).flatMap(([mId, months]) => 
              Object.entries(months).map(([month, data]) => ({
                ...(typeof data === 'object' ? data : { value: data }),
                memberId: mId,
                month: month,
                id: `${mId}-${month}`
              }))
            );
            setPoints(flattened);
          } else {
            setPoints(pointsData);
          }
        }

        if (allData.lockedSaturdays) setLockedSaturdays(allData.lockedSaturdays);
        if (allData.units) setUnits(Array.isArray(allData.units) ? allData.units : []);
        if (allData.users) setUsers(allData.users);
        if (allData.inventory) setInventory(allData.inventory);
        if (allData.inventoryCategories && Array.isArray(allData.inventoryCategories)) {
          setInventoryCategories(allData.inventoryCategories);
        } else {
          setInventoryCategories(['Camping Gear', 'Cooking', 'Uniforms', 'Electronics', 'Furniture', 'Flags/Banners', 'Other']);
        }
        if (allData.cuotaAmount) setCuotaAmount(allData.cuotaAmount);
        if (allData.masterGuideData) setMasterGuideData(allData.masterGuideData);
        if (allData.financeCategories) setFinanceCategories(allData.financeCategories);
        if (allData.tents) setTents(allData.tents);
        if (allData.tentAssignments) setTentAssignments(allData.tentAssignments);
        if (allData.duesConfig) {
          setDuesStartDate(allData.duesConfig.startDate || '');
          setSkippedSaturdays(allData.duesConfig.skippedSaturdays || []);
        }
        if (allData.uniformInspections) setUniformInspections(allData.uniformInspections);
        if (allData.memberUniforms) setMemberUniforms(allData.memberUniforms);
        if (allData.uniformItems && Array.isArray(allData.uniformItems)) {
          setUniformItems(allData.uniformItems);
        }
        if (allData.uniformCategories && Array.isArray(allData.uniformCategories)) {
          setUniformCategories(allData.uniformCategories);
        }

        // Robust loading for Qualifications (Handle Object vs Array)
        if (allData.qualifications) {
          const qualData = allData.qualifications;
          if (typeof qualData === 'object' && !Array.isArray(qualData)) {
            console.log('🔄 Autofix: Converting Qualifications Map to List...');
            const flattened = Object.entries(qualData).map(([mId, data]) => ({
              ...(typeof data === 'object' ? data : { scores: data }),
              memberId: mId,
              id: mId
            }));
            setQualifications(flattened);
          } else {
            setQualifications(qualData);
          }
        }

        if (allData.clubSettings) setClubSettings(allData.clubSettings);
        if (allData.fixedPaymentConcepts) setFixedPaymentConcepts(allData.fixedPaymentConcepts);
        if (allData.fixedPayments) setFixedPayments(allData.fixedPayments);
        if (allData.reminders) setReminders(allData.reminders);
        if (allData.attendanceRecords) setAttendanceRecords(allData.attendanceRecords);
        if (allData.campDetails) setCampDetails(allData.campDetails);
        if (allData.classRequirements) setClassRequirements(allData.classRequirements);
        if (allData.evaluationGroups) setEvaluationGroups(allData.evaluationGroups);
        if (allData.memberProgress) setMemberProgress(allData.memberProgress);
        if (allData.requirementSections) setRequirementSections(allData.requirementSections);
        if (allData.firstAidItems) setFirstAidItems(allData.firstAidItems);
        if (allData.disciplineRecords) setDisciplineRecords(allData.disciplineRecords);
        if (allData.announcements) setAnnouncements(allData.announcements);


        setDataLoaded(true); // Enable auto-save now that we have loaded data
        console.log('✅ Data loaded successfully!');
      } catch (error) {
        console.error('❌ Error loading data:', error);
        // Optionally set an error state here to show a specific message
      }
    };

    fetchData();
  }, [isAuthenticated, portalMember]);

  const syncPortalData = async (isManual = false) => {
    if (isManual) setIsSyncingPortal(true);
    try {
      console.log(`${isManual ? '🖱️' : '🚀'} Iniciando sincronización HÍBRIDA (Maestro + Pantalla)...`);
      const keysToMigrate = ['members', 'points', 'units', 'disciplineRecords', 'announcements', 'attendanceRecords', 'qualifications', 'uniformInspections', 'homeworks', 'memberHomeworkStatus', 'memberProgress'];
      
      // Load all Master Members FIRST for identity mapping
      const cloudMembers = await dataService.readData('members') || [];
      const masterMembers = cloudMembers.length > 0 ? cloudMembers : (members || []);
      console.log(`👤 Miembros para resolución: ${masterMembers.length} (${cloudMembers.length > 0 ? 'Desde Nube' : 'Desde Pantalla'}).`);

      const findGuid = (idOrCode) => {
        if (!idOrCode) return null;
        const search = String(idOrCode).trim().toLowerCase();
        const found = masterMembers.find(m => 
          String(m.id).toLowerCase() === search || 
          String(m.portalAccessCode || '').toLowerCase() === search
        );
        if (found) return found.id;

        const normalize = (s) => s.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();
        const searchNorm = normalize(search);
        const nameMatch = masterMembers.find(m => {
           const fullName = normalize((m.firstName || '') + ' ' + (m.lastName || '')).trim();
           return fullName === searchNorm || normalize(m.firstName || '') === searchNorm;
        });
        return nameMatch ? nameMatch.id : idOrCode;
      };

      for (const key of keysToMigrate) {
        // LAYER 1: Load from Cloud Master
        console.log(`🔍 Buscando '${key}' en Nube...`);
        let cloudData = await dataService.readData(key);
        
        // LAYER 2: Fallback to Current Screen State variables
        // Map keys to their actual React State variable names
        const screenData = {
          'members': members,
          'points': points,
          'units': units, 
          'disciplineRecords': disciplineRecords,
          'announcements': announcements, 
          'attendanceRecords': attendanceRecords,
          'qualifications': memberProgress // FIXED: qualifications is stored in memberProgress state
        }[key];

        // DEBUG: Log state content to identify where the data is
        if (screenData) {
          const sCount = Array.isArray(screenData) ? screenData.length : Object.keys(screenData).length;
          console.log(`📱 PANTALLA [${key}]: Encontrados ${sCount} registros en memoria del navegador.`);
        } else {
          console.log(`📱 PANTALLA [${key}]: Variable de estado vacía o nula.`);
        }

        let dataToMigrate = cloudData;
        let source = 'Nube';

        const isDataEmpty = (d) => !d || (Array.isArray(d) ? d.length === 0 : Object.keys(d).length === 0);

        if (isDataEmpty(dataToMigrate) && !isDataEmpty(screenData)) {
           dataToMigrate = screenData;
           source = 'PANTALLA (Local)';
           console.log(`💡 '${key}' está vacío en nube, USANDO DATOS DE LA PANTALLA (${source}).`);
        }

        if (isDataEmpty(dataToMigrate)) {
          console.warn(`⚠️ Omitiendo '${key}': No se encontró información en Nube ni Pantalla.`);
          continue;
        }

        console.log(`📦 Procesando registros de '${key}' (Fuente: ${source})...`);
        let normalizedData = dataToMigrate;

        // Flattening + Identity resolution
        if (key === 'points' && !Array.isArray(dataToMigrate)) {
          console.log(`🔄 Aplanando objeto de puntos para ${Object.keys(dataToMigrate).length} miembros...`);
          normalizedData = Object.entries(dataToMigrate).flatMap(([rawId, monthlyData]) => {
            const actualId = findGuid(rawId);
            if (monthlyData && typeof monthlyData === 'object') {
              return Object.entries(monthlyData).map(([month, record]) => {
                const base = typeof record === 'object' && record !== null ? record : { value: record };
                return { ...base, memberId: actualId, month: month, id: `${actualId}-${month}` };
              });
            } else if (monthlyData !== undefined && monthlyData !== null) {
              return [{ memberId: actualId, value: monthlyData, id: `flat-${actualId}-${Date.now()}` }];
            }
            return [];
          });
        } 
        else if (key === 'qualifications' && !Array.isArray(dataToMigrate)) {
          console.log(`🔄 Aplanando matriz de progreso para ${Object.keys(dataToMigrate).length} miembros...`);
          normalizedData = Object.entries(dataToMigrate).flatMap(([mId, reqs]) => {
             const actualId = findGuid(mId);
             if (reqs && typeof reqs === 'object') {
                return Object.entries(reqs).map(([reqId, status]) => ({
                   memberId: actualId,
                   requirementId: reqId,
                   ...(typeof status === 'object' ? status : { status }),
                   id: `${actualId}-${reqId}`
                }));
             }
             return [];
          });
        }
        else if (Array.isArray(dataToMigrate)) {
           normalizedData = dataToMigrate.map(item => {
              if (item.memberId) return { ...item, memberId: findGuid(item.memberId) };
              if (item.responsibleId) return { ...item, responsibleId: findGuid(item.responsibleId) };
              if (item.id && key === 'members') return { ...item, memberId: item.id };
              return item;
           });
        }
        else if (typeof dataToMigrate === 'object') {
          normalizedData = Object.entries(dataToMigrate).map(([id, val]) => {
            const actualId = findGuid(id);
            const base = typeof val === 'object' && val !== null ? val : { value: val };
            return { ...base, id: actualId, memberId: actualId };
          });
        }
        
        console.log(`📤 Subiendo ${normalizedData.length || 1} registros de '${key}' al portal...`);
        // CRITICAL: We now use skipMaster: true so we DON'T overwrite the admin's master file with flattened portal data!
        await dataService.writeData(key, normalizedData, { skipMaster: true });
      }
      console.log('✅ Sincronización Híbrida completada (Sin afectar Master Doc).');
      if (isManual) alert('¡Sincronización FINAL completada! Los datos se han subido al portal SIN alterar tus archivos maestros.');
    } catch (err) {
      console.error('❌ Error en sincronización:', err);
      if (isManual) alert('Error: ' + err.message);
    } finally {
      if (isManual) setIsSyncingPortal(false);
    }
  };

  // 🚑 EMERGENCY DATA RECOVERY: Restore Master Docs from Portal Collections
  const repairSystemData = async () => {
    if (!window.confirm('🚨 ¿Deseas ejecutar la REPARACIÓN DE EMERGENCIA? \n\nEsto intentará reconstruir tus tablas de méritos y unidades usando los datos del portal. Rompiste tu panel por la sincronización anterior, esto lo arreglará.')) return;
    
    setIsSyncingPortal(true);
    try {
      console.log('🚑 Iniciando Operación de Rescate...');
      
      // 1. Recover Points (The most critical failure)
      console.log('⏳ Recuperando PUNTOS...');
      const portalPoints = await dataService.readData('points') || [];
      if (Array.isArray(portalPoints) && portalPoints.length > 0) {
        const reconstructedPoints = {};
        portalPoints.forEach(p => {
          const month = p.month || p.monthKey;
          if (p.memberId && month) {
            if (!reconstructedPoints[p.memberId]) reconstructedPoints[p.memberId] = {};
            reconstructedPoints[p.memberId][month] = p;
          }
        });
        console.log(`✅ Puntos reconstruidos: ${Object.keys(reconstructedPoints).length} miembros.`);
        await dataService.writeData('points', reconstructedPoints);
        setPoints(portalPoints); // portalPoints is the array format from readData
      }

      // 2. Recover Member Progress (Member Progress)
      console.log('⏳ Recuperando PROGRESO DE CLASES...');
      const portalProgress = await dataService.readData('memberProgress') || [];
      if (Array.isArray(portalProgress) && portalProgress.length > 0) {
        const reconstructedProgress = {};
        portalProgress.forEach(q => {
          if (q.memberId && q.requirementId) {
            if (!reconstructedProgress[q.memberId]) reconstructedProgress[q.memberId] = {};
            reconstructedProgress[q.memberId][q.requirementId] = q;
          }
        });
        console.log(`✅ Progreso reconstruido: ${Object.keys(reconstructedProgress).length} miembros.`);
        await dataService.writeData('memberProgress', reconstructedProgress);
        setMemberProgress(reconstructedProgress);
      }

      // 3. Recover Units
      console.log('⏳ Recuperando UNIDADES...');
      const portalUnits = await dataService.readData('units') || [];
      if (Array.isArray(portalUnits) && portalUnits.length > 0) {
        await dataService.writeData('units', portalUnits);
        setUnits(portalUnits);
        console.log(`✅ Unidades restauradas: ${portalUnits.length}`);
      }

      alert('🎉 ¡REPARACIÓN EXITOSA! \n\nTus puntos, progreso y unidades han sido restaurados al formato de administrador. Por favor recarga la página.');
      window.location.reload();
    } catch (err) {
      console.error('❌ Error en reparación:', err);
      alert('Error en reparación: ' + err.message);
    } finally {
      setIsSyncingPortal(false);
    }
  };

  // TRIGGER: Automatic Migration (Run by Admin on Login)
  useEffect(() => {
    console.log('🔄 Verificando estado para sincronización portal:', { 
      isAuthenticated, 
      dataLoaded, 
      role: currentUser?.role 
    });
    
    if (isAuthenticated && dataLoaded && currentUser?.role === 'administrator') {
      const timer = setTimeout(() => syncPortalData(false), 5000);
      return () => clearTimeout(timer);
    }
  }, [isAuthenticated, dataLoaded, currentUser]);

  // ========================================
  // AUTO-SAVE DATA ON CHANGES
  // ========================================
  useEffect(() => {
    const saveData = async () => {
      // SAFETY CHECK: Only save if data has been successfully loaded from disk.
      if (!dataLoaded) return;

      // Secondary check: ensure we at least have users (admin always exists)
      if (users.length === 0) return;

      const dataToSave = {
        members,
        transactions,
        activities,
        points,
        lockedSaturdays,
        units,
        users,
        inventory,
        cuotaAmount,
        masterGuideData,
        announcements,
        financeCategories,
        // paymentConcepts, concepts, achievements removed as they are undefined
        reminders,
        inventoryCategories,
        tents,
        tentAssignments,
        uniformInspections,
        memberUniforms,
        uniformItems,
        uniformCategories,
        clubSettings,
        duesConfig: {
          startDate: duesStartDate,
          skippedSaturdays
        },
        qualifications,
        disciplineRecords,
        fixedPaymentConcepts,
        fixedPayments,
        attendanceRecords,
        campDetails,
        classRequirements,
        evaluationGroups,
        memberProgress,
        requirementSections,
        firstAidItems,
        homeworks,
        memberHomeworkStatus
      };

      try {
        // SAFETY: Only save if we have dataLoaded flag TRUE
        if (!dataLoaded) return;

        // CRITICAL DATA INTEGRITY CHECK:
        // Protect cloud from accidental wipe if loading failed
        if (members.length === 0 && activities.length === 0 && users.length > 0) {
           console.warn("🛑 Safety trigger: Data state is unexpectedly empty. Aborting save.");
           return;
        }
        
        // If we have members but 0 activities, and we had activities before...
        // This is harder to check without previous state, but we can at least 
        // prevent a save if we are in a 'syncing' error state.
        if (syncStatus === 'error') {
           console.error("🛑 Aborting save due to previous sync error.");
           return;
        }

        setSyncStatus('saving');
        // SANITIZATION STEP:
        const cleanData = JSON.parse(JSON.stringify(dataToSave));
        await saveToElectron(cleanData);
        setSyncStatus('saved');
        setHasUnsavedChanges(false);
        
        // Return to idle after a few seconds
        setTimeout(() => setSyncStatus(prev => prev === 'saved' ? 'idle' : prev), 3000);
      } catch (err) {
        console.error("Error sanitizing/saving data:", err);
        setSyncStatus('error');
      }
    };

    if (dataLoaded) {
      setHasUnsavedChanges(true);
    }
    const debounceSave = setTimeout(saveData, 500); // Debounce saves (faster for draft feel)
    return () => clearTimeout(debounceSave);

  }, [members, transactions, activities, points, lockedSaturdays, units, users, cuotaAmount, inventory, inventoryCategories, masterGuideData, financeCategories, duesStartDate, skippedSaturdays, tents, tentAssignments, uniformItems, uniformCategories, clubSettings, qualifications, fixedPaymentConcepts, fixedPayments, attendanceRecords, campDetails, classRequirements, evaluationGroups, memberProgress, requirementSections, firstAidItems, disciplineRecords, memberUniforms, uniformInspections, reminders, homeworks, memberHomeworkStatus, dataLoaded, retryTrigger]);

  // ========================================

  // === RBAC: Get module access level for current user ===
  // Returns: 'write' (full access), 'read' (view only), 'none' (hidden/no access)
  const getModuleAccessLevel = (moduleId) => {
    if (!currentUser) return 'none';
    
    // 1. MASTER BYPASS: Cloud owner and Master Admin always have full access
    const masterEmails = ['jeancarlosbzpn@gmail.com', 'soybaex@gmail.com'];
    if (masterEmails.includes(currentUser.email)) return 'write';
    if (currentUser.role === 'administrator') return 'write';
    if (currentUser.username === 'soybaex') return 'write';

    // 2. GRANULAR PERMISSIONS: Check new modulePermissions object first
    const modulePermissions = currentUser.modulePermissions || {};
    if (modulePermissions[moduleId]) {
      if (modulePermissions[moduleId] === 'edit') return 'write';
      if (modulePermissions[moduleId] === 'read') return 'read';
      if (modulePermissions[moduleId] === 'none') return 'none';
    }

    // 3. LEGACY GRANULAR PERMISSIONS: Check allowedModules array if defined
    const explicitModules = currentUser.allowedModules || [];
    if (Array.isArray(explicitModules) && explicitModules.length > 0) {
      if (!explicitModules.includes(moduleId)) {
        return 'none'; // Strictly follow the explicitly allowed list if provided
      }
    }

    const pos = currentUser.position || '';
    const positions = currentUser.positions || (pos ? [pos] : []);

    // Positions with WRITE access per module
    const writeAccess = {
      'dashboard':    ['Director','Subdirector','Secretario','Secretary','DUMC','Tesorera','Treasurer','Consejero','Instructor','Capitan'],
      'discipline':   ['Director','Subdirector','Secretario','Secretary','DUMC'],
      'activities':   ['Director','Subdirector','Secretario','Secretary'],
      'ranking':      ['Director','Subdirector','Secretario','Secretary'],
      'master_guide': ['Director','Subdirector','Secretario','Secretary'],
      'birthdays':    ['Director','Subdirector','Secretario','Secretary'],
      'directive':    ['Director','Subdirector'],
      'members':      ['Director','Subdirector','Secretario','Secretary'],
      'classes':      ['Director','Subdirector','Secretario','Secretary'],
      'units':        ['Director','Subdirector','Secretario','Secretary'],
      'medical':      ['Director','Subdirector','Secretario','Secretary'],
      'parents':      ['Director','Subdirector','Secretario','Secretary'],
      'qualifications':['Director','Subdirector','Secretario','Secretary'],
      'finances':     ['Director','Tesorera','Treasurer'],
      'cuotas':       ['Director','Tesorera','Treasurer'],
      'inventory':    ['Director','Subdirector','Secretario','Secretary'],
      'camps':        ['Director','Subdirector','Secretario','Secretary','DUMC'],
      'uniformity':   ['Director','Subdirector','Secretario','Secretary','DUMC'],
      'reports':      ['Director','Subdirector','Secretario','Secretary','DUMC'],
      'idcards':      ['Director','Subdirector','Secretario','Secretary','DUMC'],
      'points':       ['Director','Subdirector','Secretario','Secretary','DUMC'],
      'attendance':   ['Director','Subdirector','Secretario','Secretary'],
      'reminders':    ['Director','Subdirector','Secretario','Secretary'],
      'homeworks':    ['Director','Subdirector','Secretario','Secretary','DUMC','Instructor','Class Instructor'],
      'settings':     ['Director'],
    };

    // Check for write access
    const writers = writeAccess[moduleId] || [];
    if (writers.some(w => positions.includes(w))) return 'write';

    // Modules that are CRITICAL and should be hidden from regular members (Read access denied)
    const restrictedModules = new Set(['finances','cuotas','points','reminders','settings','directive','inventory']);

    if (restrictedModules.has(moduleId)) return 'none';

    // Default: Allow all authenticated members to READ non-sensitive club data
    return 'read';
  };

