  // Calculate age from date of birth
  const calculateEdad = (dob) => {
    if (!dob) return '';
    const today = new Date();
    const birthDate = new Date(dob);
    let age = today.getFullYear() - birthDate.getFullYear();
    const monthDiff = today.getMonth() - birthDate.getMonth();
    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
      age--;
    }
    return age;
  };

  // Update age when date of birth changes
  useEffect(() => {
    if (formData.dateOfBirth) {
      const age = calculateEdad(formData.dateOfBirth);
      setFormData(prev => ({ ...prev, age: age.toString() }));
    }
  }, [formData.dateOfBirth]);

  // Validation function
  const validateForm = () => {
    const newErrors = {};

    if (!formData.firstName.trim()) newErrors.firstName = 'El nombre es obligatorio';
    if (!formData.lastName.trim()) newErrors.lastName = 'El apellido es obligatorio';
    if (!formData.dateOfBirth) newErrors.dateOfBirth = 'La fecha de nacimiento es obligatoria';
    // bloodType is now optional — no validation required
    if (!formData.gender) newErrors.gender = 'El género es obligatorio';
    if (!formData.address.trim()) newErrors.address = 'La dirección es obligatoria';
    if (!formData.primaryContact.trim()) newErrors.primaryContact = 'El contacto principal es obligatorio';

    // Parent info only required if under 18
    if (parseInt(formData.age) < 18) {
      const hasFather = formData.fatherName && formData.fatherName.trim();
      const hasMother = formData.motherName && formData.motherName.trim();

      if (!hasFather && !hasMother) {
        newErrors.fatherName = "Debe registrar al menos uno de los padres";
        newErrors.motherName = "Debe registrar al menos uno de los padres";
      }

      // If father is listed, his contact is required? (User didn't specify strictness here, but logical)
      // Actually user said: "si ya puse el nombre de la madre, que el nombre y el número del padre deje de ser obligatorio"
      // implying if I put father, father contact might be required, but mother contact not.
      // Let's assume standard field validation: if name is present, contact should probably be there, OR just name is enough.
      // Based on user request: "así mismo con el número de teléfono de los padres"
      // So if father provided -> father phone might be needed. If mother provided -> mother phone needed.
      // But user essentially wants to ABANDON the other parent's fields.

      // Let's keep it simple: Validate contact only if name is provided.
      // BUT if neither name provided, we already flagged an error above.
    }

    // if (!formData.religion.trim()) newErrors.religion = 'La religión es obligatoria';

    // Medical-Emergency contact is required
    if (!formData.emergencyContactName.trim()) newErrors.emergencyContactName = 'El contacto de emergencia es obligatorio';
    if (!formData.emergencyContactRelationship.trim()) newErrors.emergencyContactRelationship = 'El parentesco es obligatorio';
    if (!formData.emergencyContactPhone.trim()) newErrors.emergencyContactPhone = 'El teléfono de emergencia es obligatorio';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

